// src/pages/HomePage.js
import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useSensor } from '../hooks/useSensor';
import './HomePage.css';

const HomePage = () => {
    const navigate = useNavigate();
    const { user } = useAuth();
    const { status, loading } = useSensor();

    const solutions = [
        {
            id: 1,
            title: 'Guardian Care',
            logo: '🛡️',
            description: 'Major medical events, emergencies, advanced imaging, private hospitalisation, surgery, cancer treatment and international evacuations.',
            color: '#4f2f7c',
            link: '/solutions/guardian-care'
        },
        {
            id: 2,
            title: 'Access Care',
            logo: '🚪',
            description: 'Emergency services, hospital admissions, consultations with doctors and specialists, diagnostic imaging, and outpatient treatment.',
            color: '#2c3e50',
            link: '/solutions/access-care'
        },
        {
            id: 3,
            title: 'Vantage Care',
            logo: '⭐',
            description: 'Management of chronic conditions, maternity care, dental services, optical equipment, wellness and preventative care.',
            color: '#27ae60',
            link: '/solutions/vantage-care'
        }
    ];

    const quickLinks = [
        { icon: '📦', title: 'Products', link: '/solutions' },
        { icon: '📝', title: 'Register', link: '/register' },
        { icon: '🔐', title: 'Login', link: '/login' },
        { icon: '💳', title: 'Make Payment', link: '/payment' }
    ];

    return (
        <div className="homepage">
            {/* Hero Section */}
            <section className="hero-section">
                <div className="hero-content">
                    <h1>Solutions</h1>
                    <p>
                        Healthguard members and policyholders can enjoy the benefits of private health care services 
                        for their healthcare needs, subject to the benefit limits and restrictions applicable to their 
                        scheme, throughout the SADC region, sub-Saharan Africa and India.
                    </p>
                </div>
            </section>

            {/* Solutions Section */}
            <section className="solutions-section">
                <div className="container">
                    <div className="solutions-grid">
                        {solutions.map((solution) => (
                            <div 
                                key={solution.id} 
                                className="solution-card"
                                onClick={() => navigate(solution.link)}
                            >
                                <div className="solution-logo" style={{ backgroundColor: solution.color }}>
                                    <span className="logo-icon">{solution.logo}</span>
                                </div>
                                <div className="solution-content">
                                    <h3>{solution.title}</h3>
                                    <p>{solution.description}</p>
                                    <button className="btn-more">More information →</button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Quick Links Section */}
            <section className="quicklinks-section">
                <div className="container">
                    <h2 className="section-title">Quick Links</h2>
                    <div className="quicklinks-grid">
                        {quickLinks.map((link, index) => (
                            <div 
                                key={index} 
                                className="quicklink-card"
                                onClick={() => navigate(link.link)}
                            >
                                <div className="quicklink-icon">{link.icon}</div>
                                <h3>{link.title}</h3>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Sensor Status Section */}
            <section className="sensor-status-section">
                <div className="container">
                    <div className="sensor-card">
                        <div className="sensor-icon">🔒</div>
                        <div className="sensor-info">
                            <h3>Fingerprint Authentication</h3>
                            <p>
                                {loading ? (
                                    'Checking sensor status...'
                                ) : status.connected ? (
                                    '✅ Fingerprint sensor is connected and ready'
                                ) : (
                                    '⚠️ Fingerprint sensor not connected. You can still use password login.'
                                )}
                            </p>
                            {!user && (
                                <div className="sensor-actions">
                                    <button 
                                        className="btn-primary"
                                        onClick={() => navigate('/login')}
                                    >
                                        Login
                                    </button>
                                    <button 
                                        className="btn-secondary"
                                        onClick={() => navigate('/register')}
                                    >
                                        Register
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default HomePage;
